'use client';
import { useState } from 'react';
import { AppShell } from '@/components/AppShell';
import { ChecklistItem } from '@/components/ChecklistItem';
import { createClient } from '@/lib/supabaseClient';
export default function MeuDia(){const supabase=createClient();const [state,setState]=useState({workout_done:false,meals_ok:false,habit_done:false,water_liters:2,energy:4,mood:4,sleep_quality:4});const [msg,setMsg]=useState('');async function complete(){const {data:{user}}=await supabase.auth.getUser();if(!user)return;const date=new Date().toISOString().slice(0,10);const {error}=await supabase.from('daily_progress').upsert({user_id:user.id,date,...state,completed:true},{onConflict:'user_id,date'});setMsg(error?error.message:'Dia concluído! Você fortaleceu sua nova identidade hoje.')}return <AppShell><h1 className="text-4xl font-black">Meu Dia</h1><p className="mt-2 text-slate-600">Execute o essencial de hoje. Simples, claro e consistente.</p><div className="mt-6 grid gap-4 md:grid-cols-2"><div className="card"><h2 className="text-xl font-black">Checklist</h2><div className="mt-4 grid gap-3"><ChecklistItem label="Treino recomendado concluído" checked={state.workout_done} onChange={v=>setState({...state,workout_done:v})}/><ChecklistItem label="Refeições alinhadas" checked={state.meals_ok} onChange={v=>setState({...state,meals_ok:v})}/><ChecklistItem label="Hábito saudável do dia" checked={state.habit_done} onChange={v=>setState({...state,habit_done:v})}/></div><label className="mt-4 block text-sm font-semibold">Água: {state.water_liters}L</label><input type="range" min="0" max="4" step="0.5" value={state.water_liters} onChange={e=>setState({...state,water_liters:+e.target.value})} className="w-full"/><button className="btn mt-5" onClick={complete}>Marcar dia como concluído</button>{msg&&<p className="mt-3 rounded-2xl bg-brand-50 p-3 text-brand-700">{msg}</p>}</div><div className="grid gap-4"><div className="card"><h2 className="font-black">Treino recomendado</h2><p className="mt-2 text-slate-600">Agachamento, remada, supino/flexão, desenvolvimento e caminhada leve.</p></div><div className="card"><h2 className="font-black">Refeição sugerida</h2><p className="mt-2 text-slate-600">Arroz, feijão, frango grelhado, salada colorida e fruta.</p></div><div className="card"><h2 className="font-black">Hábito do dia</h2><p className="mt-2 text-slate-600">Dormir 30 minutos mais cedo e deixar a garrafa de água visível.</p></div></div></div></AppShell>}
