export function ChecklistItem({label,checked,onChange}:{label:string;checked:boolean;onChange:(v:boolean)=>void}){return <label className="flex items-center gap-3 rounded-2xl border bg-white p-4"><input type="checkbox" checked={checked} onChange={e=>onChange(e.target.checked)} className="h-5 w-5"/><span className={checked?'font-semibold text-brand-700':'font-medium'}>{label}</span></label>}
